import math

def solution(limit: int = 1500000) -> int:
    """
    Further optimized singular triple count using an array and a more direct m loop.
    """
    counts = [0] * (limit + 1)

    for m in range(2, int(math.sqrt(limit / 2)) + 1):
        # Optimization: start n from 1 if m is even, else 2. Step by 2.
        start_n = 1 if m % 2 == 0 else 2
        for n in range(start_n, m, 2):
            if math.gcd(m, n) == 1:
                p = 2 * m * (m + n)
                if p > limit: break
                # Use a while loop or range to mark all multiples
                for multiple_p in range(p, limit + 1, p):
                    counts[multiple_p] += 1

    return counts.count(1)


if __name__ == "__main__":
    print(solution(1500000))
